"use client"

import { useContext, useEffect, useState } from "react"
import { ProfileContext } from "../../context/profile/ProfileContext"
import Spinner from "../layout/Spinner"
import axios from "axios"

const LinkedInPosts = () => {
  const { profile } = useContext(ProfileContext)
  const [linkedinData, setLinkedinData] = useState(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)

  useEffect(() => {
    const fetchLinkedInData = async () => {
      if (profile) {
        const linkedinPlatform = profile.platforms.find((p) => p.name === "LinkedIn")
        if (linkedinPlatform) {
          try {
            setLoading(true)
            const res = await axios.get("/api/linkedin/posts")

            if (res.data.success) {
              setLinkedinData(res.data.data)
            } else {
              setError({
                message: res.data.message || "Failed to fetch LinkedIn data",
                details: res.data.requiredSetup || res.data.alternatives || [],
              })
            }
          } catch (err) {
            console.error("Error fetching LinkedIn data:", err)
            setError({
              message: "Failed to connect to LinkedIn API",
              details: ["LinkedIn API integration requires authentication and user consent"],
            })
          } finally {
            setLoading(false)
          }
        } else {
          setLoading(false)
        }
      }
    }

    fetchLinkedInData()
  }, [profile])

  if (loading) {
    return <Spinner />
  }

  if (error) {
    return (
      <div className="bg-white p-4 rounded-lg shadow-md">
        <h3 className="text-xl font-semibold mb-2">LinkedIn Activity</h3>
        <div className="p-4 bg-yellow-50 border border-yellow-200 rounded-md">
          <p className="font-medium text-yellow-800 mb-2">{error.message}</p>
          {error.details && error.details.length > 0 && (
            <ul className="list-disc pl-5 text-sm text-yellow-700">
              {error.details.map((detail, index) => (
                <li key={index}>{detail}</li>
              ))}
            </ul>
          )}
        </div>
        <div className="mt-4">
          <p className="text-gray-600">
            LinkedIn doesn't provide public API access to profile data without authentication. To integrate with
            LinkedIn:
          </p>
          <ul className="list-disc pl-5 mt-2 text-gray-600">
            <li>Register a LinkedIn Developer application</li>
            <li>Implement OAuth 2.0 authentication flow</li>
            <li>Request user consent to access their data</li>
            <li>Use LinkedIn's API with appropriate scopes</li>
          </ul>
          <p className="mt-2 text-gray-600">
            For now, you can manually add your LinkedIn profile URL to your DevLink profile.
          </p>
        </div>
      </div>
    )
  }

  if (!linkedinData) {
    return (
      <div className="bg-white p-4 rounded-lg shadow-md">
        <h3 className="text-xl font-semibold mb-2">LinkedIn Activity</h3>
        <p>Add your LinkedIn profile to see your activity here.</p>
      </div>
    )
  }

  // Format date
  const formatDate = (dateString) => {
    const options = { year: "numeric", month: "short", day: "numeric" }
    return new Date(dateString).toLocaleDateString(undefined, options)
  }

  return (
    <div className="bg-white p-4 rounded-lg shadow-md">
      <h3 className="text-xl font-semibold mb-4">LinkedIn Activity</h3>

      <div className="grid grid-cols-2 gap-4 mb-4">
        <div className="bg-gray-100 p-3 rounded">
          <p className="text-sm text-gray-600">Connections</p>
          <p className="text-xl font-bold">{linkedinData.profileSummary?.connections || "N/A"}</p>
        </div>
        <div className="bg-gray-100 p-3 rounded">
          <p className="text-sm text-gray-600">Profile Views</p>
          <p className="text-xl font-bold">{linkedinData.profileSummary?.profileViews || "N/A"}</p>
        </div>
        <div className="bg-gray-100 p-3 rounded">
          <p className="text-sm text-gray-600">Post Impressions</p>
          <p className="text-xl font-bold">{linkedinData.profileSummary?.postImpressions || "N/A"}</p>
        </div>
        <div className="bg-gray-100 p-3 rounded">
          <p className="text-sm text-gray-600">Engagement Rate</p>
          <p className="text-xl font-bold">{linkedinData.profileSummary?.engagementRate || "N/A"}%</p>
        </div>
      </div>

      <h4 className="font-semibold mb-2">Recent Posts</h4>
      {linkedinData.posts && linkedinData.posts.length > 0 ? (
        <div className="space-y-4">
          {linkedinData.posts.map((post) => (
            <div key={post.id} className="border rounded-lg p-3">
              <p className="mb-2">{post.content}</p>
              <div className="flex justify-between text-sm text-gray-500 mb-2">
                <span>{formatDate(post.date)}</span>
                <div className="flex space-x-3">
                  <span>👍 {post.likes}</span>
                  <span>💬 {post.comments}</span>
                  <span>🔄 {post.shares}</span>
                </div>
              </div>

              {post.commenters && post.commenters.length > 0 && (
                <div className="mt-3 border-t pt-2">
                  <p className="text-sm font-medium mb-1">Recent Comments:</p>
                  {post.commenters.map((commenter, idx) => (
                    <div key={idx} className="bg-gray-50 p-2 rounded mb-1 text-sm">
                      <div className="flex justify-between">
                        <span className="font-medium">{commenter.name}</span>
                        <span className="text-xs text-gray-500">{formatDate(commenter.date)}</span>
                      </div>
                      <p>{commenter.comment}</p>
                    </div>
                  ))}
                </div>
              )}
            </div>
          ))}
        </div>
      ) : (
        <div className="p-4 bg-gray-50 rounded-md">
          <p>No posts available. LinkedIn API integration requires authentication.</p>
        </div>
      )}
    </div>
  )
}

export default LinkedInPosts
